const {EventEmitter} = require('events');

class DataStream extends EventEmitter {
  processData(dataChunks) {
    for (let i = 0; i < dataChunks.length; i++) {
      this.emit('chunk', dataChunks[i]);
    }
  }
}

module.exports = DataStream;
EOF
